<!DOCTYPE html>
<html lang="en">
  <head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Tooltip Fade Animation</title>
    <script src="script.js" defer></script>
    <link rel="stylesheet" href="styles.css">
  </head>
  <body>
    <button class="bg-gray-800 hover:bg-gray-900 text-white font-bold py-2 px-4 rounded" id="button">Hover me!</button>
    <div class="tooltip absolute opacity-0" id="tooltip">Tooltip text</div>
  </body>
</html>
styles.css
@tailwind base;
@tailwind components;
@tailwind utilities;
.tooltip {
  position: absolute;
  background-color: #333;
  color: #fff;
  padding: 10px;
  border-radius: 10px;
  opacity: 0;
}
.tooltip.show {
  opacity: 1;
  transform: translate(-50%, -100%);
}
script.js
document.addEventListener('DOMContentLoaded', function() {
  const button = document.getElementById('button');
  const tooltip = document.getElementById('tooltip');
  button.addEventListener('mouseover', function() {
    tooltip.classList.add('show');
  });
  button.addEventListener('mouseout', function() {
    tooltip.classList.remove('show');
  });
});
